svg.script:
const MODES = [
  { title:'LOCALIZED OUTPUT',    engLabel:'SUPERDTP',  engSub:'LOCALIZATION ENGINE',    stat:'75+',  statSub:'LANGUAGES'  },
  { title:'DTP OUTPUT',          engLabel:'SUPERDTP',  engSub:'DESKTOP PUBLISHING',     stat:'DTP',  statSub:'READY'      },
  { title:'COMPLIANCE OUTPUT',   engLabel:'SUPERDTP',  engSub:'PDF REMEDIATION ENGINE', stat:'§508', statSub:'WCAG 2.1'   },
  { title:'E-LEARNING OUTPUT',   engLabel:'SUPERDTP',  engSub:'E-LEARNING ENGINE',      stat:'SCRM', statSub:'2004 READY' },
  { title:'QA VERIFIED OUTPUT',  engLabel:'SUPERDTP',  engSub:'QUALITY ASSURANCE',      stat:'99%',  statSub:'ACCURACY'   }
];

let current = 0;
const panels     = document.querySelectorAll('.mode-panel');
const panelTitle = document.getElementById('panel-title');
const engLabel   = document.getElementById('eng-mode-label');
const engSub     = document.getElementById('eng-sub-label');
const engStat    = document.getElementById('eng-stat');
const engStatSub = document.getElementById('eng-stat-sub');
const dots       = document.querySelectorAll('[id^="dot-"]');

function switchMode(next) {
  panels[current].classList.remove('active');
  dots[current].setAttribute('r','3');
  dots[current].setAttribute('fill','rgba(255,255,255,.2)');
  current = next;
  const m = MODES[current];
  panelTitle.textContent = m.title;
  engLabel.textContent   = m.engLabel;
  engSub.textContent     = m.engSub;
  engStat.textContent    = m.stat;
  engStatSub.textContent = m.statSub;
  panels[current].classList.add('active');
  dots[current].setAttribute('r','4');
  dots[current].setAttribute('fill','#d4af37');
}

setInterval(function() { switchMode((current + 1) % MODES.length); }, 4000);
